            onBatchSubmit={async (input) => {
              await subsApi.batchCreate(input);
            }}
            onSuccess={() => {
              setCreateOpen(false);
              mutate("subscriptions");
            }}
            onCancel={() => setCreateOpen(false)}
          />
        </DialogContent>
      </Dialog>

      {/* Edit dialog */}
      <Dialog
        open={!!editingSub}
        onOpenChange={(open) => {
          if (!open) setEditingSub(null);
        }}
      >
        <DialogContent className="sm:max-w-lg">
